scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "OP603",
    compID: "gr_master:coilType"
  }];
  $c.data.setCommonCode($p, codeOptions);
  $c.gus.cfTurnCreateFlag($p, true);
};
scwin.onUdcCompleted = function () {
  scwin.f_FieldClear();
  scwin.f_SetSrchDefault();
  if (ed_pdaClntNo.getValue() == "100008" || ed_pdaClntNo.getValue() == "239616" || ed_pdaClntNo.getValue() == "247256") {
    $c.gus.cfEnableObj($p, ed_pdaClntNo, false);
    $c.gus.cfEnableObj($p, txt_pdaClntNm, false);
    $c.gus.cfEnableObj($p, btn_clntNo, false);
  }
  if (ed_pdaClntNo.getValue() == "") {
    ed_pdaClntNo.setValue("");
  }
  scwin.f_retrieve();
};

//////////////////////////////////////////////////////////////////////////
// 조회 실행  f_retrieve()
//////////////////////////////////////////////////////////////////////////		
scwin.f_retrieve = async function () {
  if (!(await $c.gus.cfValidate($p, [tb_searchCondition]))) {
    return;
  }
  $c.sbm.execute($p, sbm_condition);
};

//-----------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
scwin.f_runExcel = async function () {
  if ($c.gus.cfIsNull($p, gr_master)) {
    return;
  }
  if ($c.gus.cfIsNull($p, ds_master)) {
    return;
  }
  var totCnt = ds_master.getTotalRow();
  var fileName = "배차정보";
  if (totCnt != 0) {
    var cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      await $c.data.downloadGridViewExcel($p, gr_master, {
        fileName: fileName + ".xlsx",
        sheetName: fileName
      });
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
  }
};

