//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_save = async function () {
  if (ds_master.getTotalRow() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }

  // if (!ds_master.IsUpdated) {
  if (ds_master.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["배차정보"]);
    return;
  }
  var cnt = 0;
  ds_save.removeAll();
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    for (var i = 0; i < ds_master.getTotalRow(); i++) {
      if (ds_master.getRowStatus(i) == "U") {
        ds_save.insertRow(cnt);
        $c.gus.f_CopyDataRow($p, ds_master, ds_save, i, cnt);
        cnt++;
      }
    }
    $c.sbm.execute($p, sbm_master);
  }
};

//-------------------------------------------------------------------------
// 배차확정
//-------------------------------------------------------------------------
scwin.f_confirm = async function () {
  var j = 0;
  var cnt = 0;
  for (var i = 0; i < ds_master.getTotalRow(); i++) {
    if (ds_master.getCellData(i, 'chk') == "1") {
      j = j + 1;
    }
  }
  if (j < 1) {
    await $c.win.alert($p, "배차확정을 할 코일을 선택해 주세요");
    return false;
  } else {
    ds_out.removeAll();
    if (await $c.win.confirm($p, "배차확정을 하시겠습니까?")) {
      for (var s = 0; s < ds_master.getTotalRow(); s++) {
        if (ds_master.getCellData(s, "chk") == "1") {
          if (ds_master.getCellData(s, "etDt") == "") {
            await $c.win.alert($p, "배차확정 시 출고예정일자는 필수값입니다.");
            return;
          }
          ds_out.insertRow(cnt);
          $c.gus.f_CopyDataRow($p, ds_master, ds_out, s, cnt);
          cnt++;
        }
      }
      $c.sbm.execute($p, sbm_confirm);
    }
  }
};

//-------------------------------------------------------------------------
// 배차취소
//-------------------------------------------------------------------------
scwin.f_cancel = async function () {
  var j = 0;
  var cnt = 0;
  for (var i = 0; i < ds_master.getTotalRow(); i++) {
    if (ds_master.getCellData(i, 'chk') == "1") {
      j = j + 1;
    }
  }
  if (j < 1) {
    await $c.win.alert($p, "배차취소 할 코일을 선택해 주세요");
    return false;
  } else {
    ds_cancel.removeAll();
    if (await $c.win.confirm($p, "배차취소를 하시겠습니까?")) {
      for (var s = 0; s < ds_master.getTotalRow(); s++) {
        if (ds_master.getCellData(s, "chk") == "1") {
          if (ds_master.getCellData(s, "confirmYn") != 1) {
            await $c.win.alert($p, "배차확정상태인 코일만 배차취소가 가능합니다.");
            return;
          }
          ds_cancel.insertRow(cnt);
          $c.gus.f_CopyDataRow($p, ds_master, ds_cancel, s, cnt);
          cnt++;
        }
      }
      $c.sbm.execute($p, sbm_cancel);
    }
  }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode, pAllSearch) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', pAllSearch);
    // inObj가 코드명 필드일 경우 팝업
  } else {
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', pAllSearch);
  }
};

// 그리드 차량번호 팝업
scwin.f_OpenGridPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch, pClickTF) {
  // 선언부
  var rtnList; // 공통POP-UP -> 요청화면 
  scwin.g_search_fag = 0; //글로벌변수: 화종조회 초기화

  switch (disGubun) {
    case 1:
      // 정비사 팝업	
      var carNo = ds_master.getCellData(scwin.selectedRowIndex, "carNo"); //차량코드	
      var newData = ds_master.getCellData(scwin.selectedRowIndex, 'carNm'); //차량번호
      var oldData = $c.gus.f_GetGridHidden($p, ds_master, scwin.selectedRowIndex, 'carNm');
      if (pClickTF == "T") {
        if (!$c.gus.f_CanGridPopup($p, ds_master, 'carNm', newData, oldData, ["carNo", "carNm"])) {
          return false;
        }
      }
      if (scwin.onPopup) {
        scwin.onPopup = false;
        ds_master.setCellData(scwin.selectedRowIndex, "carNm", "");
        udc_gr_carNm.setSelectId("retrieveModexCarListInfo");
        await udc_gr_carNm.cfCommonPopUp(scwin.callBackFun, pCode // 화면에서의 Code Element의	Value
        , pName // 화면에서의 Name Element의	Value
        , pClose // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        , null // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        , null // Title순서	
        , null // 보여주는 각 컬럼들의 폭	
        , null // 컬럼중에서 숨기는	컬럼 지정	
        , null // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null // POP-UP뛰을때 원도우의	사용자 정의	폭
        , null // POP-UP뛰을때 우도우의	사용자 정의	높이	
        , null // 윈도우 위치 Y좌표	
        , null // 윈도우 위치 X좌표
        , null // 중복체크여부	("F")
        , 'F' // 전체검색허용여부	("F")
        , "차량,차량코드,차량번호" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
        );
        scwin.onPopup = true;
        break;
      } else {
        break;
      }
  }
};
scwin.callBackFun = function (rtnList) {
  if (rtnList != undefined) {
    if (rtnList[0] != "N/A") {
      $c.gus.cfSetGridReturnValue($p, rtnList, ds_master, scwin.selectedRowIndex, "carNo", "carNm");
    } else {
      // 그리드 차량번호 포커스 아웃 시 조회 팝업에서 미선택(x 또는 닫기) 시 그리드 차량번호 초기화
      ds_master.setCellData(scwin.selectedRowIndex, "carNo", scwin.oldCarNo);
      ds_master.setCellData(scwin.selectedRowIndex, "carNm", scwin.oldCarNm);
    }
  }
};
